SELECT COUNT(SP.PK) AS QUANTIDADE FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(SP.PAPEL) = LOWER('coordenador') AND LOWER(P.TIPO_PROJETO) LIKE LOWER('extens%') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%educacao fisica%' AND LOWER(S.SIGLA_CAMPUS) = LOWER('itu') AND P.DATA_INICIO >= DATE('now', '-5 years')